css:
.print-heading {
  text-align: center;
  margin-bottom: 28px;
}

.print-heading h2 {
  margin: 0;
  font-size: 18pt;
}

.print-heading p {
  margin: 6px 0 0;
}

.employee-summary {
  margin-bottom: 20px;
}

.summary-table,
.dismissal-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 20px;
}

.summary-table th,
.summary-table td,
.dismissal-table th,
.dismissal-table td {
  padding: 8px;
  border: 1px solid #d7d7d7;
  vertical-align: top;
}

.summary-table tbody tr:nth-child(odd),
.dismissal-table tbody tr:nth-child(odd) {
  background-color: #fafafa;
}

.summary-label {
  width: 18%;
  font-weight: 600;
  background-color: #f4f4f4;
}

.dismissal-table th {
  background-color: #f4f4f4;
  text-align: left;
  font-weight: 600;
}

.dismissal-table tr {
  page-break-inside: avoid;
}

.number-column {
  width: 38px;
  text-align: center;
}

.date-column {
  width: 110px;
  white-space: nowrap;
}

.empty-row {
  text-align: center;
  color: #777;
  font-style: italic;
}

.dismissal-notice {
  margin: 18px 0 22px;
  padding: 14px 16px;
  border: 1px solid #d5b0b0;
  border-left: 4px solid #a40000;
  background-color: #fff8f8;
  page-break-inside: avoid;
}

.dismissal-notice p {
  margin: 0 0 10px;
}

.dismissal-notice p:last-child {
  margin-bottom: 0;
}

.section-heading {
  margin-top: 22px;
  margin-bottom: 10px;
  padding-bottom: 5px;
  border-bottom: 1px solid #a40000;
  font-size: 12pt;
  font-weight: 600;
  page-break-after: avoid;
}

.acknowledgement {
  margin-top: 22px;
}

.acknowledgement p {
  margin: 0 0 10px;
}

.signatures {
  margin-top: 28px;
}

.signatures table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

.signatures tr {
  page-break-inside: avoid;
}

.signatures td {
  border: none;
  vertical-align: bottom;
}

.signatures .signature-cell {
  width: 68%;
  padding: 38px 30px 16px 0;
}

.signatures .date-cell {
  width: 32%;
  padding: 38px 0 16px 20px;
}

.signatures .signature-line {
  min-height: 22px;
  border-bottom: 1px solid #222;
}

.signatures .signature-label {
  margin-top: 5px;
  font-size: 10.5pt;
  line-height: 1.3;
}

.signatures .qualifier {
  font-size: 9pt;
  font-style: italic;
}
